/**
 * @fileoverview Phrase-signer Zcash wallet — the "connect with a seed phrase"
 * path, sibling of the cosign `CosignWalletService` for wallets whose
 * spending key lives in this tab rather than split across devices.
 *
 * Pipeline: derive UFVK/UA from the BIP-39 phrase → witness-scan via the
 * wallet scanner → server-side `/pczt/build` → local `signPczt` → broadcast.
 * Mirrors Secresea's mnemonic send over the kit's shared PCZT plumbing
 * (`buildShieldedPczt` / `broadcastPczt`).
 *
 * The key material never leaves the host: derivation and signing are injected
 * via {@link PhraseWalletAdapter} (WebZjs `derive_usk_from_mnemonic` +
 * `pczt_sign`, or equivalent) so the kit ships no WASM and the phrase is held
 * only in this service's memory for the tab lifetime.
 */

import { createWalletScannerClient, type WalletScannerClientType } from '../scanner/zcashScannerClient';
import { resolveCosignConfig, type CosignConfig } from '../cosign/config';
import { broadcastPczt } from '../cosign/cosignSend';
import { buildShieldedPczt, scanUfvkNotes, toZatoshis, toZec } from '../cosign/initiator';
import type { CosignBalance } from '../cosign/walletService';
import type { CosignCallbacks } from '../cosign/relay';

const DEFAULT_SCANNER_BASE_URL = '/api';
const HEX64 = /^[0-9a-fA-F]{64}$/;

/**
 * Host-supplied key operations for the phrase path. Both calls receive the
 * normalised phrase so the adapter can stay stateless.
 */
export interface PhraseWalletAdapter {
	/** Derive the wallet's viewing surface (and signing metadata) from a phrase. */
	deriveFromPhrase: (phrase: string, accountIndex: number) => Promise<{
		ufvk: string;
		unifiedAddress: string;
		/** ZIP-32 seed fingerprint (64 hex) — required by `/pczt/build`. */
		seedFingerprintHex: string;
		/** Internal (change) address; defaults to `unifiedAddress` when omitted. */
		changeAddress?: string;
	}>;
	/** Sign an unsigned PCZT (base64) locally; return the signed PCZT (base64). */
	signPczt: (unsignedPcztBase64: string, phrase: string, accountIndex: number) => Promise<string>;
}

export interface PhraseWalletDeps {
	adapter: PhraseWalletAdapter;
	config?: Partial<CosignConfig>;
	scannerBaseUrl?: string;
	scannerApiKey?: string;
	scannerClient?: WalletScannerClientType;
}

export interface LoadedPhraseWallet {
	ufvk: string;
	unifiedAddress: string;
	seedFingerprintHex: string;
	accountIndex: number;
}

export interface PhraseSendOptions {
	toAddress: string;
	amountZec: number;
	memo?: string;
	birthdayHeight?: number;
	callbacks?: CosignCallbacks;
}

export interface PhraseWalletSendResult {
	txid: string;
	signedPczt: string;
}

const normalisePhrase = (phrase: string): string =>
	String(phrase || '').trim().toLowerCase().replace(/\s+/g, ' ');

/** True when the text is shaped like a BIP-39 phrase (12/24 lowercase words). */
export const looksLikeSeedPhrase = (text: string): boolean => {
	const words = normalisePhrase(text).split(' ').filter(Boolean);
	return (words.length === 12 || words.length === 24)
		&& words.every((w) => /^[a-z]+$/.test(w));
};

export class PhraseWalletService {
	private readonly config: Readonly<CosignConfig>;
	private readonly deps: PhraseWalletDeps;
	private phrase: string | null = null;
	private changeAddress: string | null = null;
	private loaded: LoadedPhraseWallet | null = null;

	constructor(deps: PhraseWalletDeps) {
		this.deps = deps;
		this.config = resolveCosignConfig(deps.config);
	}

	getConfig(): Readonly<CosignConfig> {
		return this.config;
	}

	getWallet(): LoadedPhraseWallet | null {
		return this.loaded;
	}

	isLoaded(): boolean {
		return this.loaded !== null;
	}

	private scanner(): WalletScannerClientType {
		return this.deps.scannerClient ?? createWalletScannerClient({
			baseUrl: this.deps.scannerBaseUrl ?? DEFAULT_SCANNER_BASE_URL,
			apiKey: this.deps.scannerApiKey,
		});
	}

	/**
	 * Connect with a BIP-39 phrase. The phrase is held in memory for the tab
	 * lifetime (nothing persisted) and wiped by {@link forget}.
	 */
	async connect(phrase: string, accountIndex = 0): Promise<LoadedPhraseWallet> {
		const normalised = normalisePhrase(phrase);
		if (!looksLikeSeedPhrase(normalised)) {
			throw new Error('That does not look like a BIP-39 seed phrase (12 or 24 words).');
		}
		const derived = await this.deps.adapter.deriveFromPhrase(normalised, accountIndex);
		if (!derived?.ufvk || !derived.ufvk.startsWith('uview')) {
			throw new Error('Could not derive a UFVK (uview1…) from this phrase.');
		}
		if (!derived.unifiedAddress || !derived.unifiedAddress.startsWith('u')) {
			throw new Error('Could not derive a unified address (u1…) from this phrase.');
		}
		if (!HEX64.test(derived.seedFingerprintHex || '')) {
			throw new Error('ZIP-32 seed fingerprint must be 64 hex characters (32 bytes).');
		}
		this.phrase = normalised;
		this.changeAddress = derived.changeAddress || derived.unifiedAddress;
		this.loaded = {
			ufvk: derived.ufvk,
			unifiedAddress: derived.unifiedAddress,
			seedFingerprintHex: derived.seedFingerprintHex,
			accountIndex,
		};
		return this.loaded;
	}

	forget(): void {
		this.phrase = null;
		this.changeAddress = null;
		this.loaded = null;
	}

	async getBalance(birthdayHeight?: number, signal?: AbortSignal): Promise<CosignBalance> {
		if (!this.loaded) throw new Error('Connect a seed phrase first.');
		const notes = await scanUfvkNotes({
			scanner: this.scanner(),
			ufvk: this.loaded.ufvk,
			birthdayHeight,
			apiKey: this.deps.scannerApiKey,
			signal,
		});
		const balanceZatoshis = notes.reduce((sum, n) => sum + Number(n.value || 0), 0);
		return { balanceZatoshis, balanceZec: toZec(balanceZatoshis), noteCount: notes.length };
	}

	async send(opts: PhraseSendOptions): Promise<PhraseWalletSendResult> {
		if (!this.loaded || !this.phrase) throw new Error('Connect a seed phrase first.');
		const { callbacks } = opts;

		const built = await buildShieldedPczt({
			config: this.config,
			scanner: this.scanner(),
			scannerApiKey: this.deps.scannerApiKey,
			ufvk: this.loaded.ufvk,
			changeAddress: this.changeAddress ?? this.loaded.unifiedAddress,
			seedFingerprintHex: this.loaded.seedFingerprintHex,
			accountIndex: this.loaded.accountIndex,
			toAddress: opts.toAddress,
			amountZat: toZatoshis(opts.amountZec),
			memoText: opts.memo,
			birthdayHeight: opts.birthdayHeight,
			signal: callbacks?.signal,
			onProgress: callbacks?.onProgress,
		});

		callbacks?.onProgress?.('Signing in this tab...');
		const signedPczt = await this.deps.adapter.signPczt(built.pczt, this.phrase, this.loaded.accountIndex);
		if (!signedPczt) throw new Error('The signer returned no signed PCZT.');

		callbacks?.onProgress?.('Broadcasting transaction...');
		const broadcast = await broadcastPczt(this.config, signedPczt, 'base64');
		if (!broadcast?.txid) throw new Error('Broadcast returned no txid.');

		callbacks?.onProgress?.('Transaction broadcast.');
		return { txid: broadcast.txid, signedPczt };
	}
}
