/**
 * Framework-agnostic Cosign wallet controller (Secresea's CosignWalletService
 * without React/host wiring). Load one `.wult` Orchard FROST share, scan
 * balance, and send via {@link runHeadlessCosignSend}.
 */

import { createWalletScannerClient, type WalletScannerClientType } from '../scanner/zcashScannerClient';
import { resolveCosignConfig, type CosignConfig } from './config';
import {
	deriveOrchardAddressFromBundle,
	loadOrchardFrostWasm,
	type OrchardFrostWasmModule,
	type OrchardKeyBundle,
} from './orchardFrost';
import { unwrapVaultShare } from './vaultShare';
import { deriveZcashSeedFromVaultIdentity } from './seed';
import {
	runHeadlessCosignSend,
	scanUfvkNotes,
	toOrchardBundle,
	toZatoshis,
	toZec,
} from './initiator';
import type { CosignCallbacks } from './relay';
import type { CosignTransport } from './transports';

const DEFAULT_SCANNER_BASE_URL = '/api';
const HEX64 = /^[0-9a-fA-F]{64}$/;

export interface LoadedCosignWallet {
	ufvk: string;
	unifiedAddress: string;
	seedFingerprintHex: string | null;
	identifier: string;
	minSigners: number;
	maxSigners: number;
}

export interface CosignBalance {
	balanceZatoshis: number;
	balanceZec: number;
	noteCount: number;
}

export interface CosignSendOptions {
	toAddress: string;
	amountZec: number;
	memo?: string;
	birthdayHeight?: number;
	onQrReady?: (qrPayload: string) => void;
	callbacks?: CosignCallbacks;
}

export interface CosignWalletSendResult {
	txid: string;
	signedPczt: string;
}

export interface CosignWalletDeps {
	config?: Partial<CosignConfig>;
	scannerBaseUrl?: string;
	scannerApiKey?: string;
	loadWasm?: (config: CosignConfig) => Promise<OrchardFrostWasmModule>;
	/** Optional ZIP-32 seed fingerprint (hex) for PCZT metadata. */
	computeSeedFingerprint?: (seed64: Uint8Array) => Promise<string>;
	scannerClient?: WalletScannerClientType;
	createTransport?: (sessionId: string, encKeyHex: string) => CosignTransport;
	/** Derive a 64-byte Zcash seed from vault identity (optional). */
	deriveSeedFromIdentity?: (hexChainCode: string, publicKeyEcdsa: string) => Promise<Uint8Array>;
}

export class CosignWalletService {
	private readonly config: Readonly<CosignConfig>;
	private readonly deps: CosignWalletDeps;
	private wasm: OrchardFrostWasmModule | null = null;
	private bundle: OrchardKeyBundle | null = null;
	private loaded: LoadedCosignWallet | null = null;

	constructor(deps: CosignWalletDeps = {}) {
		this.deps = deps;
		this.config = resolveCosignConfig(deps.config);
	}

	getConfig(): Readonly<CosignConfig> {
		return this.config;
	}

	getWallet(): LoadedCosignWallet | null {
		return this.loaded;
	}

	isLoaded(): boolean {
		return this.loaded !== null;
	}

	private async ensureWasm(): Promise<OrchardFrostWasmModule> {
		if (!this.wasm) {
			this.wasm = await (this.deps.loadWasm ?? loadOrchardFrostWasm)(this.config);
		}
		return this.wasm;
	}

	private scanner(): WalletScannerClientType {
		return this.deps.scannerClient ?? createWalletScannerClient({
			baseUrl: this.deps.scannerBaseUrl ?? DEFAULT_SCANNER_BASE_URL,
			apiKey: this.deps.scannerApiKey,
		});
	}

	/**
	 * Load a `.wult` share, derive UFVK/UA, hold the decrypted share in memory
	 * for the tab lifetime (nothing persisted).
	 */
	async loadShare(content: string, password?: string): Promise<LoadedCosignWallet> {
		const share = await unwrapVaultShare(content, password);
		if (!share.orchardFrost) {
			throw new Error('This share has no Orchard FROST key — co-sign sends Orchard (shielded ZEC) only.');
		}
		const bundle = toOrchardBundle(share.orchardFrost);
		const wasm = await this.ensureWasm();
		const addr = deriveOrchardAddressFromBundle(wasm, bundle);
		if (!addr?.ufvk || !addr?.unifiedAddress) {
			throw new Error('Could not derive a Zcash address from this FROST share (incompatible or outdated WASM).');
		}

		let seedFingerprintHex: string | null = null;
		if (share.crossChainIdentity) {
			const derive = this.deps.deriveSeedFromIdentity ?? deriveZcashSeedFromVaultIdentity;
			const seed = await derive(
				share.crossChainIdentity.hexChainCode,
				share.crossChainIdentity.publicKeyEcdsa,
			);
			if (!this.deps.computeSeedFingerprint) {
				throw new Error(
					'This host must provide computeSeedFingerprint (ZIP-32 SeedFingerprint) to build PCZTs — wire WebZjs SeedFingerprint or equivalent.',
				);
			}
			seedFingerprintHex = await this.deps.computeSeedFingerprint(seed);
			if (!seedFingerprintHex || !HEX64.test(seedFingerprintHex)) {
				throw new Error('ZIP-32 seed fingerprint must be 64 hex characters (32 bytes).');
			}
		}

		this.bundle = bundle;
		this.loaded = {
			ufvk: addr.ufvk,
			unifiedAddress: addr.unifiedAddress,
			seedFingerprintHex,
			identifier: bundle.myShare.id,
			minSigners: Number(bundle.minSigners ?? 2),
			maxSigners: Number(bundle.maxSigners ?? 2),
		};
		return this.loaded;
	}

	forget(): void {
		this.bundle = null;
		this.loaded = null;
	}

	async getBalance(birthdayHeight?: number, signal?: AbortSignal): Promise<CosignBalance> {
		if (!this.loaded) throw new Error('Load a co-signing share first.');
		const notes = await scanUfvkNotes({
			scanner: this.scanner(),
			ufvk: this.loaded.ufvk,
			birthdayHeight,
			apiKey: this.deps.scannerApiKey,
			signal,
		});
		const balanceZatoshis = notes.reduce((sum, n) => sum + Number(n.value || 0), 0);
		return { balanceZatoshis, balanceZec: toZec(balanceZatoshis), noteCount: notes.length };
	}

	async send(opts: CosignSendOptions): Promise<CosignWalletSendResult> {
		if (!this.loaded || !this.bundle) throw new Error('Load a co-signing share first.');
		if (!this.loaded.seedFingerprintHex || !HEX64.test(this.loaded.seedFingerprintHex)) {
			throw new Error(
				'This .wult is missing vault identity (crossChainIdentity) needed for PCZT metadata. Re-export the share from Winbit32 with vault identity included.',
			);
		}
		const wasm = await this.ensureWasm();
		const result = await runHeadlessCosignSend({
			config: this.config,
			wasm,
			bundle: this.bundle,
			ufvk: this.loaded.ufvk,
			unifiedAddress: this.loaded.unifiedAddress,
			seedFingerprintHex: this.loaded.seedFingerprintHex,
			scanner: this.scanner(),
			scannerApiKey: this.deps.scannerApiKey,
			toAddress: opts.toAddress,
			amountZat: toZatoshis(opts.amountZec),
			memoText: opts.memo,
			birthdayHeight: opts.birthdayHeight,
			onQrReady: (qr) => { opts.onQrReady?.(qr); },
			createTransport: this.deps.createTransport,
			callbacks: opts.callbacks,
			display: {
				chain: 'Zcash',
				ticker: 'ZEC',
				amount: String(opts.amountZec),
				toAddress: opts.toAddress,
				memo: opts.memo || '',
			},
		});
		return { txid: result.txid, signedPczt: result.signedPczt };
	}
}
