/**
 * Embeddable Winbit32 wallet bar + connect/send modal (vanilla DOM).
 *
 * Same experience as Secresea's WalletStatusBar / wallet modals, without
 * React: fixed bottom strip, connect → seed phrase or `.wult` vault share,
 * balance scan, send. A `.wult` share co-signs over the WB32COSIGN pairing QR;
 * a seed phrase signs locally in this tab (host supplies the signer via
 * {@link Winbit32WalletBarOptions.phraseAdapter}). Hosts call
 * {@link mountWinbit32WalletBar}.
 */

import { CosignWalletService, type CosignWalletDeps } from '../cosign/walletService';
import {
	PhraseWalletService,
	looksLikeSeedPhrase,
	type PhraseWalletAdapter,
} from '../zcash/phraseWalletService';

const STYLE_ID = 'wb32-wallet-bar-style';
const DEFAULT_COSIGNER_URL = 'https://winbit32.com/#cosign';
const DEFAULT_LOGO = 'https://winbit32.com/logo192.png';

/** What the bar exposes about the connected wallet, whichever way it connected. */
export interface WalletBarConnectedWallet {
	kind: 'cosign' | 'phrase';
	ufvk: string;
	unifiedAddress: string;
	/** Co-sign (.wult) wallets only. */
	minSigners?: number;
	maxSigners?: number;
}

export interface Winbit32WalletBarOptions {
	/** Mount point; defaults to document.body. */
	parent?: HTMLElement;
	/** Cosign / scanner deps (same-origin `/api` + `/orchard-frost` by default). */
	deps?: CosignWalletDeps;
	/**
	 * Enables "connect with a seed phrase" (signs locally in this tab). The
	 * host supplies key derivation + PCZT signing (WebZjs or equivalent) —
	 * without this, only `.wult` co-sign shares connect.
	 */
	phraseAdapter?: PhraseWalletAdapter;
	cosignerUrl?: string;
	logoUrl?: string;
	/**
	 * Optional file→share-text reader (e.g. extract a locket PNG `wbZt` chunk).
	 * Defaults to `file.text()`.
	 */
	readShareFile?: (file: File) => Promise<string>;
	/** Prefill the send form (e.g. campaign UA). */
	defaultToAddress?: string;
	defaultAmountZec?: string | number;
	defaultMemo?: string;
	/** Hide/lock the recipient field (campaign donate). */
	lockToAddress?: boolean;
	/** Show amount/memo send form as soon as a wallet is connected. */
	showSendOnConnect?: boolean;
	/** Open the connect modal immediately. */
	autoOpen?: boolean;
	onConnected?: (wallet: WalletBarConnectedWallet) => void;
	onDisconnected?: () => void;
	onSendComplete?: (txid: string) => void;
	onProgress?: (message: string) => void;
	onError?: (message: string) => void;
}

export interface Winbit32WalletBarHandle {
	open: () => void;
	close: () => void;
	disconnect: () => void;
	destroy: () => void;
	getWallet: () => WalletBarConnectedWallet | null;
	/** Prefill / update the send form fields. */
	setSendDefaults: (opts: { toAddress?: string; amountZec?: string | number; memo?: string }) => void;
	send: (opts?: { toAddress?: string; amountZec?: number; memo?: string }) => Promise<{ txid: string }>;
}

